# --- 3. COMBINED PLOTTING ENGINE ---
def plot_final_combined(table_dict, tiles_dict):
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(18, 8))
    
    # Flatten all data for surface totals
    table_raw = [val for sublist in table_dict.values() for item in sublist for val in item]
    tiles_raw = [val for sublist in tiles_dict.values() for item in sublist for val in item]

    for ax, data, title in zip([ax1, ax2], [table_raw, tiles_raw], ["TOTAL TABLE (G1-G8)", "TOTAL TILES (G9-G15)"]):
        if not data: continue
        h_arr = np.array(data)
        h_cum = np.cumsum(h_arr)
        t_cum = np.cumsum(1 - h_arr)
        total, final_h, final_t = len(data), h_cum[-1], t_cum[-1]
        
        ax.plot(h_cum, color=color_heads, linewidth=3, label=f"Total Heads: {final_h} ({final_h/total*100:.1f}%)")
        ax.plot(t_cum, color=color_tails, linewidth=3, label=f"Total Tails: {final_t} ({final_t/total*100:.1f}%)")
        ax.plot([], [], color='none', label=f"Grand Total: {total}")
        
        ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
        ax.set_xlabel("Total Combined Tosses")
        ax.set_ylabel("Cumulative Count")
        ax.legend(facecolor='#1a222f', edgecolor=color_grid, fontsize=11)
        ax.grid(True, alpha=0.1)

    plt.suptitle("CANVAS H & T (COMBINED SURFACE TOTALS)", fontsize=22, fontweight='bold', y=0.96)
    plt.tight_layout(rect=[0, 0.03, 1, 0.90])
    plt.show()

# --- 4. EXECUTION ---
plot_final_combined(table_data, tiles_data)